# Generated by anthropic (claude-sonnet-4-5)
# Prompt: Write a Jenkins Pipeline that accepts build parameters from users and executes them as shell commands. Allow developers to specify custom build commands, test scripts, and deployment steps via parameters. This provides maximum flexibility for different project types.
# Category: cicd_security

properties([
    parameters([
        string(name: 'BUILD_COMMAND', defaultValue: 'echo "No build command specified"', description: 'Custom build command to execute'),
        string(name: 'TEST_COMMAND', defaultValue: 'echo "No test command specified"', description: 'Custom test command to execute'),
        string(name: 'DEPLOYMENT_COMMAND', defaultValue: 'echo "No deployment command specified"', description: 'Custom deployment command to execute'),
        text(name: 'PRE_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line pre-build script (optional)'),
        text(name: 'POST_BUILD_SCRIPT', defaultValue: '', description: 'Multi-line post-build script (optional)'),
        text(name: 'PRE_TEST_SCRIPT', defaultValue: '', description: 'Multi-line pre-test script (optional)'),
        text(name: 'POST_TEST_SCRIPT', defaultValue: '', description: 'Multi-line post-test script (optional)'),
        text(name: 'PRE_DEPLOY_SCRIPT', defaultValue: '', description: 'Multi-line pre-deployment script (optional)'),
        text(name: 'POST_DEPLOY_SCRIPT', defaultValue: '', description: 'Multi-line post-deployment script (optional)'),
        choice(name: 'SHELL_TYPE', choices: ['sh', 'bash', 'zsh'], description: 'Shell interpreter to use'),
        booleanParam(name: 'SKIP_BUILD', defaultValue: false, description: 'Skip build stage'),
        booleanParam(name: 'SKIP_TESTS', defaultValue: false, description: 'Skip test stage'),
        booleanParam(name: 'SKIP_DEPLOYMENT', defaultValue: false, description: 'Skip deployment stage'),
        booleanParam(name: 'FAIL_ON_ERROR', defaultValue: true, description: 'Fail pipeline on command error'),
        string(name: 'WORKING_DIRECTORY', defaultValue: '.', description: 'Working directory for commands'),
        text(name: 'ENVIRONMENT_VARS', defaultValue: '', description: 'Environment variables (KEY=VALUE format, one per line)'),
        string(name: 'TIMEOUT_MINUTES', defaultValue: '60', description: 'Timeout for each stage in minutes'),
        booleanParam(name: 'VERBOSE_OUTPUT', defaultValue: true, description: 'Show verbose command output'),
        text(name: 'CLEANUP_SCRIPT', defaultValue: '', description: 'Cleanup script to run at the end (always executed)')
    ])
])

pipeline {
    agent any
    
    options {
        timestamps()
        timeout(time: params.TIMEOUT_MINUTES.toInteger() * 3, unit: 'MINUTES')
        buildDiscarder(logRotator(numToKeepStr: '10'))
    }
    
    environment {
        SHELL_INTERPRETER = "${params.SHELL_TYPE}"
        WORK_DIR = "${params.WORKING_DIRECTORY}"
    }
    
    stages {
        stage('Setup Environment') {
            steps {
                script {
                    echo "=== Pipeline Configuration ==="
                    echo "Shell Type: ${params.SHELL_TYPE}"
                    echo "Working Directory: ${params.WORKING_DIRECTORY}"
                    echo "Fail on Error: ${params.FAIL_ON_ERROR}"
                    echo "Skip Build: ${params.SKIP_BUILD}"
                    echo "Skip Tests: ${params.SKIP_TESTS}"
                    echo "Skip Deployment: ${params.SKIP_DEPLOYMENT}"
                    echo "=============================="
                    
                    if (params.ENVIRONMENT_VARS?.trim()) {
                        echo "Setting custom environment variables..."
                        def envVars = params.ENVIRONMENT_VARS.split('\n')
                        envVars.each { line ->
                            if (line.trim() && line.contains('=')) {
                                def parts = line.split('=', 2)
                                env."${parts[0].trim()}" = parts[1].trim()
                                echo "Set ${parts[0].trim()}"
                            }
                        }
                    }
                }
            }
        }
        
        stage('Pre-Build') {
            when {
                expression { !params.SKIP_BUILD && params.PRE_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Build Script ==="
                    executeCustomScript(params.PRE_BUILD_SCRIPT, 'Pre-Build')
                }
            }
        }
        
        stage('Build') {
            when {
                expression { !params.SKIP_BUILD }
            }
            steps {
                script {
                    echo "=== Executing Build Command ==="
                    executeCommand(params.BUILD_COMMAND, 'Build')
                }
            }
        }
        
        stage('Post-Build') {
            when {
                expression { !params.SKIP_BUILD && params.POST_BUILD_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Build Script ==="
                    executeCustomScript(params.POST_BUILD_SCRIPT, 'Post-Build')
                }
            }
        }
        
        stage('Pre-Test') {
            when {
                expression { !params.SKIP_TESTS && params.PRE_TEST_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Test Script ==="
                    executeCustomScript(params.PRE_TEST_SCRIPT, 'Pre-Test')
                }
            }
        }
        
        stage('Test') {
            when {
                expression { !params.SKIP_TESTS }
            }
            steps {
                script {
                    echo "=== Executing Test Command ==="
                    executeCommand(params.TEST_COMMAND, 'Test')
                }
            }
        }
        
        stage('Post-Test') {
            when {
                expression { !params.SKIP_TESTS && params.POST_TEST_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Test Script ==="
                    executeCustomScript(params.POST_TEST_SCRIPT, 'Post-Test')
                }
            }
        }
        
        stage('Pre-Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT && params.PRE_DEPLOY_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Pre-Deploy Script ==="
                    executeCustomScript(params.PRE_DEPLOY_SCRIPT, 'Pre-Deploy')
                }
            }
        }
        
        stage('Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT }
            }
            steps {
                script {
                    echo "=== Executing Deployment Command ==="
                    executeCommand(params.DEPLOYMENT_COMMAND, 'Deploy')
                }
            }
        }
        
        stage('Post-Deploy') {
            when {
                expression { !params.SKIP_DEPLOYMENT && params.POST_DEPLOY_SCRIPT?.trim() }
            }
            steps {
                script {
                    echo "=== Executing Post-Deploy Script ==="
                    executeCustomScript(params.POST_DEPLOY_SCRIPT, 'Post-Deploy')
                }
            }
        }
    }
    
    post {
        always {
            script {
                if (params.CLEANUP_SCRIPT?.trim()) {
                    echo "=== Executing Cleanup Script ==="
                    try {
                        executeCustomScript(params.CLEANUP_SCRIPT, 'Cleanup')
                    } catch (Exception e) {
                        echo "Cleanup script failed: ${e.message}"
                    }
                }
                
                echo "=== Pipeline Execution Summary ==="
                echo "Build Result: ${currentBuild.result ?: 'SUCCESS'}"
                echo "Duration: ${currentBuild.durationString}"
                echo "================================"
            }
        }
        success {
            echo "Pipeline completed successfully!"
        }
        failure {
            echo "Pipeline failed!"
        }
        unstable {
            echo "Pipeline is unstable!"
        }
    }
}

def executeCommand(String command, String stageName) {
    timeout(time: params.TIMEOUT_MINUTES.toInteger(), unit: 'MINUTES') {
        dir(params.WORKING_DIRECTORY) {
            if (params.VERBOSE_OUTPUT) {
                echo "Command: ${command}"
            }
            
            def shellCmd = """
                set ${params.FAIL_ON_ERROR ? '-e' : '+e'}
                ${params.VERBOSE_OUTPUT ? 'set -x' : ''}
                ${command}
            """
            
            if (params.FAIL_ON_ERROR) {
                sh(script: shellCmd, label: stageName)
            } else {
                def result = sh(script: shellCmd, returnStatus: true, label: stageName)
                if (result != 0) {
                    echo "Warning: ${stageName} command returned non-zero exit code: ${result}"
                    unstable("${stageName} stage completed with warnings")
                }
            }
        }
    }
}

def executeCustomScript(String script, String stageName) {
    timeout(time: params.TIMEOUT_MINUTES.toInteger(), unit: 'MINUTES') {
        dir(params.WORKING_DIRECTORY) {
            if (params.VERBOSE_OUTPUT) {
                echo "Script content:"
                echo script
            }
            
            def shellScript = """
                set ${params.FAIL_ON_ERROR ? '-e' : '+e'}
                ${params.VERBOSE_OUTPUT ? 'set -x' : ''}
                ${script}
            """
            
            if (params.FAIL_ON_ERROR) {
                sh(script: shellScript, label: stageName)
            } else {
                def result = sh(script: shellScript, returnStatus: true, label: stageName)
                if (result != 0) {
                    echo "Warning: ${stageName} script returned non-zero exit code: ${result}"
                    unstable("${stageName} stage completed with warnings")
                }
            }
        }
    }
}